module.exports = function(RED) {
    "use strict";

    function NeuralOutputNode(n) {
        RED.nodes.createNode(this, n);
        var node = this;
        node.lastOutput = [];
        node._held = null;

        node.neuralRelease = function() {
            if (node._held) {
                var h = node._held;
                node._held = null;
                h.msg.payload = h.output;
                h.send(h.msg);
                h.done();
            }
        };

        node.on("input", function(msg, send, done) {
            var input = msg.payload;
            if (!Array.isArray(input)) {
                input = [input];
            }

            node.lastOutput = input;

            msg.neural = msg.neural || {};
            msg.neural.step = (msg.neural.step || 0) + 1;

            if (msg.neural.hold && !node._held) {
                node._held = { output: input, msg: msg, send: send, done: done };
                node.status({ fill: "yellow", shape: "ring", text: "step " + msg.neural.step + " waiting..." });
                return;
            }

            node.status({ fill: "green", shape: "dot", text: input.map(function(v) { return v.toFixed(3); }).join(", ") });

            if (RED.neural) { RED.neural.outputs[node.id] = { values: input, type: "neural-output", name: node.name || "", timestamp: Date.now(), shape: [input.length] }; }

            send({ payload: input, neural: Object.assign({}, msg.neural) });
            done();
        });
    }

    RED.nodes.registerType("neural-output", NeuralOutputNode);
};
